const AWS = require('aws-sdk');
const https = require('https');
const http = require('http');
const { URL } = require('url');

const dynamo = new AWS.DynamoDB.DocumentClient({
  maxRetries: 2,
  httpOptions: { timeout: 2500, connectTimeout: 800 }
});

const ORDERS_TABLE = process.env.ORDERS_TABLE;
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const PAYMENT_API_KEY = process.env.PAYMENT_API_KEY || '';
const PAYMENT_TIMEOUT_MS = Number(process.env.PAYMENT_TIMEOUT_MS || 2500);
const MAX_API_RETRIES = Number(process.env.PAYMENT_MAX_RETRIES || 1);

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function httpRequestJson(urlStr, { method = 'POST', headers = {}, body, timeoutMs = 2500 } = {}) {
  return new Promise((resolve, reject) => {
    const url = new URL(urlStr);
    const isHttps = url.protocol === 'https:';
    const lib = isHttps ? https : http;

    const payload = body == null ? null : Buffer.from(JSON.stringify(body));
    const reqHeaders = {
      'accept': 'application/json',
      ...headers
    };
    if (payload) {
      reqHeaders['content-type'] = reqHeaders['content-type'] || 'application/json';
      reqHeaders['content-length'] = Buffer.byteLength(payload);
    }

    const req = lib.request(
      {
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (isHttps ? 443 : 80),
        path: url.pathname + (url.search || ''),
        method,
        headers: reqHeaders
      },
      (res) => {
        let data = '';
        res.setEncoding('utf8');
        res.on('data', (chunk) => (data += chunk));
        res.on('end', () => {
          const statusCode = res.statusCode || 0;
          let parsed = null;
          try {
            parsed = data ? JSON.parse(data) : null;
          } catch (_) {
            parsed = { raw: data };
          }
          resolve({ statusCode, headers: res.headers, body: parsed });
        });
      }
    );

    req.on('error', reject);
    req.setTimeout(timeoutMs, () => req.destroy(new Error('Request timeout')));

    if (payload) req.write(payload);
    req.end();
  });
}

async function callPaymentApi(order) {
  if (!PAYMENT_API_URL) throw new Error('PAYMENT_API_URL is not set');

  const payload = {
    orderId: order.orderId,
    amount: order.amount,
    currency: order.currency,
    paymentMethod: order.paymentMethod,
    customerId: order.customerId,
    metadata: order.metadata || {}
  };

  let lastErr;
  for (let attempt = 0; attempt <= MAX_API_RETRIES; attempt++) {
    try {
      const res = await httpRequestJson(PAYMENT_API_URL, {
        method: 'POST',
        timeoutMs: PAYMENT_TIMEOUT_MS,
        headers: {
          'authorization': PAYMENT_API_KEY ? `Bearer ${PAYMENT_API_KEY}` : undefined
        },
        body: payload
      });

      if (res.statusCode >= 200 && res.statusCode < 300) return res.body;

      const err = new Error(`Payment API non-2xx: ${res.statusCode}`);
      err.response = res.body;
      throw err;
    } catch (e) {
      lastErr = e;
      if (attempt < MAX_API_RETRIES) await sleep(50 * Math.pow(2, attempt));
    }
  }
  throw lastErr;
}

async function updateOrderStatus(orderId, update) {
  if (!ORDERS_TABLE) throw new Error('ORDERS_TABLE is not set');

  const now = new Date().toISOString();

  const exprParts = [];
  const names = { '#updatedAt': 'updatedAt' };
  const values = { ':updatedAt': now };

  exprParts.push('#updatedAt = :updatedAt');

  for (const [k, v] of Object.entries(update || {})) {
    const nk = `#${k}`;
    const vk = `:${k}`;
    names[nk] = k;
    values[vk] = v;
    exprParts.push(`${nk} = ${vk}`);
  }

  await dynamo
    .update({
      TableName: ORDERS_TABLE,
      Key: { orderId },
      UpdateExpression: 'SET ' + exprParts.join(', '),
      ExpressionAttributeNames: names,
      ExpressionAttributeValues: values
    })
    .promise();
}

function parseOrder(record) {
  const body = record.body;
  const msg = typeof body === 'string' ? JSON.parse(body) : body;
  if (!msg || !msg.orderId) throw new Error('Invalid message: missing orderId');
  return msg;
}

exports.handler = async (event) => {
  const records = Array.isArray(event.Records) ? event.Records : [];
  if (records.length === 0) return;

  await Promise.all(
    records.map(async (record) => {
      let order;
      try {
        order = parseOrder(record);
      } catch (e) {
        console.error('Failed to parse SQS message', { messageId: record.messageId, error: e && e.message, recordBody: record.body });
        return;
      }

      const orderId = order.orderId;

      try {
        await updateOrderStatus(orderId, { status: 'PROCESSING' });
      } catch (e) {
        console.error('Failed to set PROCESSING', { orderId, error: e && e.message });
      }

      let paymentResult;
      try {
        paymentResult = await callPaymentApi(order);
      } catch (e) {
        console.error('Payment API error', { orderId, error: e && e.message, details: e && e.response });
        try {
          await updateOrderStatus(orderId, { status: 'PAYMENT_FAILED', paymentError: String(e && e.message) });
        } catch (e2) {
          console.error('Failed to update PAYMENT_FAILED', { orderId, error: e2 && e2.message });
        }
        return;
      }

      try {
        await updateOrderStatus(orderId, {
          status: 'PAID',
          paymentId: paymentResult && (paymentResult.paymentId || paymentResult.id),
          paymentStatus: paymentResult && (paymentResult.status || 'PAID'),
          paymentRaw: paymentResult || null
        });
      } catch (e) {
        console.error('Failed to update PAID', { orderId, error: e && e.message });
      }
    })
  );
};